use std::time::{Duration, Instant};

struct Instruction {
    opcode: u8,
    data: Vec<i32>,
}

impl Instruction {
    fn new(opcode: u8, data: Vec<i32>) -> Self {
        Instruction { opcode, data }
    }

    fn execute_dummy(&self) -> i64 {
        let mut result = 0;
        for &item in &self.data {
            result = (result + item as i64).wrapping_add(1);
        }
        result
    }
}

fn run_benchmark(instructions: &[Instruction], iterations: usize) -> Duration {
    let start = std::time::Instant::now();
    for _ in 0..iterations {
        let mut total_result: i64 = 0;
        for instruction in instructions.iter() {
            total_result = total_result.wrapping_add(instruction.execute_dummy());
        }
    }
    std::time::Instant::now().duration_since(start)
}

fn main() {
    let base_instructions: Vec<Instruction> = vec![
        Instruction::new(0x01, vec![10, 20]),
        Instruction::new(0x02, vec![5]),
        Instruction::new(0xFF, vec![99, 1])
    ];

    let num_iterations = 1000;
    let duration = run_benchmark(&base_instructions, num_iterations);

    println!("Benchmarked execution over {} cycles took: {:?}", num_iterations, duration);
}

