use std::time::{Duration, Instant};

struct ByteCodeVM {
    memory: Vec<u8>,
    instruction_pointer: usize,
}

impl ByteCodeVM {
    fn new(size: usize) -> Self {
        ByteCodeVM {
            memory: vec![0; size],
            instruction_pointer: 0,
        }
    }

    fn execute_fetch(&self, address: usize) -> u8 {
        if self.memory.len() <= address {
            panic!("Out of bounds access");
        }
        self.memory[address]
    }

    fn run_benchmark(&mut self) -> Duration {
        let start = Instant::now();
        for i in 0..100000 {
            let val1 = self.execute_fetch(i * 4);
            let val2 = self.execute_fetch(i * 4 + 1);
            let _dummy_result: u32 = (val1 as u32).wrapping_add((val2 as u32) << 8);
        }
        start.elapsed()
    }
}

fn main() {
    const MEMORY_SIZE: usize = 4096;
    let mut vm = ByteCodeVM::new(MEMORY_SIZE);
    vm.memory[10] = 0xAA;
    vm.memory[11] = 0xBB;

    let duration = vm.run_benchmark();
    println!("Benchmark executed in: {:?}", duration);
}

use std::time::{Duration, Instant};

struct DataProcessor {
    data: Vec<i32>,
}

impl DataProcessor {
    fn new(size: usize) -> Self {
        DataProcessor { data: vec![1; size] }
    }

    fn calculate_sum_first(&self, start_index: usize, count: usize) -> i32 {
        let mut sum = 0;
        for i in start_index..(start_index + count)
        {
            sum += self.data[i];
        }
        sum
    }

    fn calculate_sum_iter(&self, start_index: usize, count: usize) -> i32 {
        let mut sum = 0;
        for i in start_index..(start_index + count)
        {
            sum += self.data[i];
        }
        sum
    }
}

fn main() {
    const DATA_SIZE: usize = 10000;
    let processor = DataProcessor::new(DATA_SIZE);
    let start_index = 10;
    let count = 50;

    println!("Benchmarking sum calculation over {} items...", count);

    let start_time = Instant::now();
    let _result_manual = processor.calculate_sum_first(start_index, count);
    let elapsed_manual = start_time.elapsed();

    let start_time = Instant::now();
    let _result_iter = processor.calculate_sum_iter(start_index, count);
    let elapsed_iter = start_time.elapsed();

    println!("Manual Loop Time: {:?}", elapsed_manual);
    println!("Iterator/Range Time: {:?}", elapsed_iter);
}

use std::collections::HashMap;

struct Cache {
    data: HashMap<String, String>,
}

impl Cache {
    fn new() -> Self {
        Cache { data: HashMap::new() }
    }

    fn set(&mut self, key: impl AsRef<str>, value: impl AsRef<str>) {
        self.data.insert(key.as_ref().to_string(), value.as_ref().to_string());
    }

    fn get(&self, key: impl AsRef<str>) -> Option<&String> {
        self.data.get(key.as_ref())}
}

fn main() {
    let mut cache = Cache::new();
    cache.set("user:1", "John Doe");
    cache.set("product:A", "Widget X");

    if let Some(name) = cache.get("user:1") {
        println!("Found user name: {}", name);
    }
}

